<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('academic.supervise');$pdo=obtenerConexion();$asignaturas=$pdo->query('SELECT a.*,COUNT(DISTINCT da.docente_id) docentes,COUNT(DISTINCT ed.estudiante_id) estudiantes FROM asignaturas a LEFT JOIN docentes_asignaturas da ON da.asignatura_id=a.id AND da.estado=\'activo\' LEFT JOIN estudiantes_docentes ed ON ed.asignatura_id=a.id AND ed.estado=\'activo\' GROUP BY a.id ORDER BY a.nombre LIMIT 200')->fetchAll();$docentes=$pdo->query("SELECT id,nombre,apellido,correo FROM usuarios WHERE rol='docente' AND estado='activo' AND deleted_at IS NULL ORDER BY nombre LIMIT 200")->fetchAll();$estudiantes=$pdo->query("SELECT id,nombre,apellido,correo FROM usuarios WHERE rol='usuario' AND estado='activo' AND deleted_at IS NULL ORDER BY nombre LIMIT 200")->fetchAll();cmsCabecera('Gestión académica','academico/index.php','Cursos, asignaciones docentes y matrículas estudiantiles.');?>
<div class="row"><div class="col-lg-4"><div class="card card-rounded mb-4"><div class="card-body"><h2 class="h5">Crear curso</h2><form method="post" action="accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="curso"><input class="form-control mb-2" name="codigo" maxlength="40" placeholder="Código" required><input class="form-control mb-2" name="nombre" maxlength="180" placeholder="Nombre" required><textarea class="form-control mb-2" name="descripcion" maxlength="5000" placeholder="Descripción"></textarea><button class="btn btn-primary w-100">Crear curso</button></form></div></div></div><div class="col-lg-4"><div class="card card-rounded mb-4"><div class="card-body"><h2 class="h5">Asignar docente</h2><form method="post" action="accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="docente"><select class="form-select mb-2" name="asignatura_id" required><option value="">Curso</option><?php foreach($asignaturas as$a):?><option value="<?=$a['id']?>"><?=atenea_e($a['nombre'])?></option><?php endforeach;?></select><select class="form-select mb-2" name="docente_id" required><option value="">Docente</option><?php foreach($docentes as$d):?><option value="<?=$d['id']?>"><?=atenea_e(trim($d['nombre'].' '.$d['apellido']))?></option><?php endforeach;?></select><button class="btn btn-primary w-100">Asignar</button></form></div></div></div><div class="col-lg-4"><div class="card card-rounded mb-4"><div class="card-body"><h2 class="h5">Matricular estudiante</h2><form method="post" action="accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="estudiante"><select class="form-select mb-2" name="asignatura_id" required><option value="">Curso</option><?php foreach($asignaturas as$a):?><option value="<?=$a['id']?>"><?=atenea_e($a['nombre'])?></option><?php endforeach;?></select><select class="form-select mb-2" name="docente_id" required><option value="">Docente asignado</option><?php foreach($docentes as$d):?><option value="<?=$d['id']?>"><?=atenea_e(trim($d['nombre'].' '.$d['apellido']))?></option><?php endforeach;?></select><select class="form-select mb-2" name="estudiante_id" required><option value="">Estudiante</option><?php foreach($estudiantes as$e):?><option value="<?=$e['id']?>"><?=atenea_e(trim($e['nombre'].' '.$e['apellido']))?></option><?php endforeach;?></select><button class="btn btn-primary w-100">Matricular</button></form></div></div></div></div><div class="card card-rounded"><div class="card-body"><div class="table-responsive"><table class="table"><thead><tr><th>Código</th><th>Curso</th><th>Estado</th><th>Docentes</th><th>Estudiantes</th></tr></thead><tbody><?php foreach($asignaturas as$a):?><tr><td><?=atenea_e($a['codigo'])?></td><td><?=atenea_e($a['nombre'])?></td><td><?=atenea_e($a['estado'])?></td><td><?=$a['docentes']?></td><td><?=$a['estudiantes']?></td></tr><?php endforeach;?><?php if(!$asignaturas):?><tr><td colspan="5" class="text-center py-5">No hay cursos creados.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();
